const output = $json.output;

const jsonMatch = output.match(/\{[\s\S]*\}/);
const parsed = JSON.parse(jsonMatch[0]);

const detectedNames = parsed.assignedTo; 
const contacts = $('mapAssignedToFetch').first().json.assignedTo;

const matched = contacts.filter(contact =>
  detectedNames.some(name => contact.name === name)
);

return [{ json: { assignedTo: matched } }];

